dark.customCSS:
/* --- NEO-TACTICAL: INDUSTRIAL CONSOLE --- */

body {
	font-family: 'JetBrains Mono', 'Roboto Mono', monospace !important;
}

/* Ventilation Grill Sidebar */
#sidebar {
	background-image: repeating-linear-gradient(0deg, rgba(0,0,0,0.2) 0px, rgba(0,0,0,0.2) 1px, transparent 1px, transparent 4px) !important;
	background-color: #0d0f12 !important;
	border-right: 2px solid #ff5f00 !important;
}

/* Tactical Corner Brackets */
.prose, .bg-gray-850 {
	background: rgba(20, 23, 26, 0.8) !important;
	border: 1px solid rgba(255, 95, 0, 0.2) !important;
	position: relative !important;
	border-radius: 0px !important;
}

.prose::before, .prose::after {
	content: '';
	position: absolute;
	width: 10px; height: 10px;
	border-color: #ff5f00;
	border-style: solid;
	pointer-events: none;
}
.prose::before { top: -2px; left: -2px; border-width: 2px 0 0 2px; }
.prose::after { bottom: -2px; right: -2px; border-width: 0 2px 2px 0; }

/* Safety-Orange Typography */
.prose h1, .prose h2 {
	color: #ff5f00 !important;
	text-transform: uppercase;
	font-weight: 800 !important;
	letter-spacing: 2px;
}
.prose h1::before {
	content: '[DECRYPTED_NODE] ';
	font-size: 0.6rem;
	opacity: 0.5;
	vertical-align: middle;
}

/* Recessed Mechanical Buttons */
button.bg-blue-500, button.bg-blue-600, .btn-primary {
	background: #ff5f00 !important;
	color: #000 !important;
	border-radius: 0px !important;
	text-transform: uppercase;
	font-weight: 900 !important;
	border: none !important;
	box-shadow: inset -2px -2px 0px rgba(0,0,0,0.4), inset 2px 2px 0px rgba(255,255,255,0.4) !important;
	transition: all 0.1s;
}

button.bg-blue-500:active {
	box-shadow: inset 2px 2px 0px rgba(0,0,0,0.4) !important;
	transform: translate(1px, 1px);
}

/* Industrial Inputs */
input, textarea {
	background: #08090a !important;
	border: 1px solid #444d56 !important;
	border-left: 4px solid #ff5f00 !important;
	color: #ff5f00 !important;
	border-radius: 0px !important;
}

/* Monochrome Scrollbar */
::-webkit-scrollbar-thumb {
	background: #444d56 !important;
	border: 1px solid #ff5f00;
}
::-webkit-scrollbar-track {
	background: #08090a !important;
}

dark.canvasScript:
/**
 * Title: Lidar Topographical Scan
 * Description: A 3D terrain wireframe that warps and reacts to mouse pressure.
 */

const CONFIG = {
    gridRes: 30,         // Resolution of the terrain
    color: 'rgba(255, 95, 0, 0.2)',
    lineColor: 'rgba(255, 95, 0, 0.4)',
    speed: 0.005,
    amplitude: 40,
    mouseForce: 100
};

let canvas, ctx, w, h;
let time = 0;
let mouse = { x: -5000, y: -5000 };

setInterval(() => self.postMessage({ type: 'heartbeat' }), 1000);

self.onmessage = (e) => {
    if (e.data.type === 'init') {
        canvas = e.data.canvas; ctx = canvas.getContext('2d');
        resize(e.data.width, e.data.height);
        render();
    } else if (e.data.type === 'resize') {
        resize(e.data.width, e.data.height);
    } else if (e.data.type === 'mousemove') {
        mouse.x = e.data.x; mouse.y = e.data.y;
    }
};

function resize(width, height) {
    w = width; h = height;
    if (canvas) { canvas.width = w; canvas.height = h; }
}

function render() {
    if (!ctx) return;
    ctx.clearRect(0, 0, w, h);
    time += CONFIG.speed;

    const cellW = w / CONFIG.gridRes;
    const cellH = h / CONFIG.gridRes;

    ctx.strokeStyle = CONFIG.lineColor;
    ctx.lineWidth = 1;

    for (let i = 0; i < CONFIG.gridRes; i++) {
        ctx.beginPath();
        for (let j = 0; j <= CONFIG.gridRes; j++) {
            let x = j * cellW;
            let y = i * cellH;

            // Procedural terrain math
            let noise = Math.sin(j * 0.2 + time) * Math.cos(i * 0.2 + time);
            let z = noise * CONFIG.amplitude;

            // Mouse warping
            let dx = mouse.x - x; let dy = mouse.y - y;
            let dist = Math.hypot(dx, dy);
            if (dist < 200) {
                z -= (1 - dist / 200) * CONFIG.mouseForce;
            }

            ctx.lineTo(x, y + z);
        }
        ctx.stroke();
    }

    // Vertical lines
    for (let j = 0; j < CONFIG.gridRes; j++) {
        ctx.beginPath();
        for (let i = 0; i <= CONFIG.gridRes; i++) {
            let x = j * cellW;
            let y = i * cellH;
            let noise = Math.sin(j * 0.2 + time) * Math.cos(i * 0.2 + time);
            let z = noise * CONFIG.amplitude;
            let dx = mouse.x - x; let dy = mouse.y - y; let dist = Math.hypot(dx, dy);
            if (dist < 200) z -= (1 - dist / 200) * CONFIG.mouseForce;
            ctx.lineTo(x, y + z);
        }
        ctx.stroke();
    }

    requestAnimationFrame(render);
}

